+{
+#if (__GNUC__ && __cplusplus && __GNUC__ >= 3)
+    int status;
+    char *res = abi::__cxa_demangle(name, 0, 0, &status);
+    if (res)
+    {
+        const std::string demangled_name(res);
+        std::free(res);
+        return demangled_name;
+    }
+    // Demangling failed, fallback to mangled name
