+void ISmaccUpdatable::executeUpdate()
+{
+    bool update = true;
+    if (periodDuration_)
+    {
+        auto now = this->nh_->get_clock()->now();
+        auto ellapsed = now - this->lastUpdate_;
+        update = ellapsed > *periodDuration_;
+        if(update)
+        {
+            this->lastUpdate_ = now;
+        }
+    }
+
+    if (update)
+    {
+        this->update();
+    }
+}
