+  void onExit() override {}
+
+  std::optional<std::string> filepath_;
+
+  std::optional<std::string> parameterName_;
+  std::optional<std::string> packageNamespace_;
+
+  cl_nav2z::CpWaypointNavigatorBase * waypointsNavigator_;
+};
